def Add(x: pd.DataFrame, y: pd.DataFrame) -> pd.DataFrame:
    result = x + y 
    return result

def Sub(x: pd.DataFrame, y: pd.DataFrame) -> pd.DataFrame:
    result = x - y 
    return result

def Mul(x: pd.DataFrame, y: pd.DataFrame) -> pd.DataFrame:
    result = x * y
    return result

def Div(x: pd.DataFrame, y: pd.DataFrame) -> pd.DataFrame:
    result = x / y
    return result

def Inv(x: pd.DataFrame) -> pd.DataFrame:
    result = 1 / x
    return result

def TS_Corr(x: pd.DataFrame, y: pd.DataFrame, d: int) -> pd.DataFrame:
    result = x.rolling(window=d).corr(y)
    return result

def TS_Std(x: pd.DataFrame, d: int) -> pd.DataFrame:
        result = x.rolling(window=d).std()
        return result

def TS_Cov(x: pd.DataFrame, y: pd.DataFrame, d: int) -> pd.DataFrame:
    result = x.rolling(window=d).cov(y)
    return result

def WMA(x: pd.DataFrame, d: int) -> pd.DataFrame:
    weights = np.arange(1, d + 1)
    return x.rolling(window=d).apply(lambda y: np.dot(y, weights) / weights.sum(), raw=True)

def Normalize(x: pd.DataFrame) -> pd.DataFrame:
    mean = x.mean(axis=1)
    std = x.std(axis=1)
    return x.sub(mean, axis=0).div(std, axis=0)

def Winsorize(x: pd.DataFrame, lower_pct: float, upper_pct: float) -> pd.DataFrame:
    lower = x.quantile(lower_pct, axis=1)
    upper = x.quantile(upper_pct, axis=1)
    return x.clip(lower=lower, upper=upper, axis=0)

def TS_Vol(x: pd.DataFrame, d: int) -> pd.DataFrame:
    returns = x.pct_change()
    return returns.rolling(window=d).std() * np.sqrt(252)

def TS_Drawdown(x: pd.DataFrame, d: int) -> pd.DataFrame:
    rolling_max = x.rolling(window=d).max()
    return (x - rolling_max) / rolling_max

def TS_Beta(x: pd.DataFrame, y: pd.DataFrame, d: int) -> pd.DataFrame:
    cov = x.rolling(window=d).cov(y)
    var = y.rolling(window=d).var()
    return cov / var

def TS_Residual(x: pd.DataFrame, y: pd.DataFrame, d: int) -> pd.DataFrame:
    cov = x.rolling(window=d).cov(y)
    var = y.rolling(window=d).var()
    beta = cov / var
    return x - beta * y

def Scale(x: pd.DataFrame, target_sum: float) -> pd.DataFrame:
    abs_sum = x.abs().sum(axis=1)
    return x.mul(target_sum, axis=0).div(abs_sum, axis=0)
